#!/bin/bash

if [ $# -eq 0 ]; then
    echo "No argument supplied, please provide a config file name."
    exit 1
fi

CONFIG_FILE=$1

if [[ ! -f /etc/configs/$CONFIG_FILE ]]; then
    echo "$CONFIG_FILE does not exist in /etc/configs/"
    exit 2
else
    cat /etc/configs/$CONFIG_FILE
fi

exit 0